
import { IMessageEvent } from '@nitrots/nitro-renderer';
import { MessageEvent } from '@nitrots/nitro-renderer';
import { ProfileAchievementsParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/ProfileAchievementsParser';

export class ProfileAchievementsEvent extends MessageEvent implements IMessageEvent
{
constructor(callBack: Function)
{
super(callBack, ProfileAchievementsParser);
}

public getParser(): ProfileAchievementsParser
{
return this.parser as ProfileAchievementsParser;
}
}